<template>

    <v-container>
        <v-dialog v-model="dialog" max-width="500px">
          <template v-slot:activator="{ on }">
            <v-btn color="primary" dark class="mb-2" v-on="on">buat minuman</v-btn>
          </template>
          <v-card>
            <v-card-title>
              <span class="headline">{{ formTitle }}</span>
            </v-card-title>
            <v-card-text>
              <v-container>
                <v-row>
                  <v-col cols="12" sm="6" md="4">
                    <v-text-field v-model="editedItem.name" label="Minuman name"></v-text-field>
                  </v-col>
                  <v-col cols="12" sm="6" md="4">
                    <v-combobox v-model="editedItem.category" :items="items" label="Category"></v-combobox>
                  </v-col>
                  <v-col cols="12" sm="6" md="4">
                    <v-text-field v-model="editedItem.fat" label="Fat (g)"></v-text-field>
                  </v-col>
                  <v-col cols="12" sm="6" md="4">
                    <v-text-field v-model="editedItem.carbs" label="Carbs (g)"></v-text-field>
                  </v-col>
                  <v-col cols="12" sm="6" md="4">
                    <v-text-field v-model="editedItem.protein" label="Protein (g)"></v-text-field>
                  </v-col>
                </v-row>
              </v-container>
            </v-card-text>
            <v-card-actions>
              <v-spacer></v-spacer>
              <v-btn color="blue darken-1" text @click="close">Cancel</v-btn>
              <v-btn color="blue darken-1" text @click="save">Save</v-btn>
            </v-card-actions>
          </v-card>
        </v-dialog>
      <v-row dense>
        <v-col cols="12">
        </v-col>

        <v-col
          v-for="(item, i) in minumans"
          :key="i"
          cols="3"
        >
          <v-card
          >
            <div class="d-flex flex-no-wrap justify-space-between">
              <div>
                <v-card-subtitle>Minuman</v-card-subtitle>
                <v-card-title
                  class="headline"
                  v-text="item.name"
                ></v-card-title>
                <v-row no-gutters>
                    <v-col>
                        <v-card-subtitle>Category</v-card-subtitle>
                    </v-col>
                    <v-col>
                        <v-card-subtitle v-text="item.category"></v-card-subtitle>
                    </v-col>
                </v-row>
                <v-row no-gutters>
                    <v-col>
                        <v-card-subtitle>Fat</v-card-subtitle>
                    </v-col>
                    <v-col>
                        <v-card-subtitle v-text="item.fat"></v-card-subtitle>
                    </v-col>
                </v-row>
                <v-row no-gutters>
                    <v-col>
                        <v-card-subtitle>Carbs</v-card-subtitle>
                    </v-col>
                    <v-col>
                        <v-card-subtitle v-text="item.carbs"></v-card-subtitle>
                    </v-col>
                </v-row>
                <v-row no-gutters>
                    <v-col>
                        <v-card-subtitle>Protein</v-card-subtitle>
                    </v-col>
                    <v-col>
                        <v-card-subtitle v-text="item.protein"></v-card-subtitle>
                    </v-col>
                </v-row>
              </div>
            </div>

            <v-card-actions>
                <v-icon class="mr-1" @click="edit(item)">mdi-border-color</v-icon>
                <v-icon class="mr-1" @click="deleteItem(item)">mdi-delete</v-icon>
            </v-card-actions>
          </v-card>
        </v-col>
      </v-row>
    </v-container>
</template>

<script>
import {minumanRef} from '../firebase';

export default {
  data: () => ({
    cek: -1,
    dialog: false,
    search: '',
    headers: [
      {
        text: 'Minuman (100g serving)',
        align: 'left',
        sortable: false,
        value: 'name',
      },
      { text: 'Category', value: 'category' },
      { text: 'Fat (g) ', value: 'fat' },
      { text: 'Carbs (g) ', value: 'carbs' },
      { text: 'Protein (g) ', value: 'protein' },
      { text: 'Actions', value: 'action', sortable: false},
    ],
    items: [
          'Es',
          'Hangat',
        ],
    minumans: [],
    editedIndex: -1,
    editedItem: {
      name: '',
      category: '',
      fat: 0,
      carbs: 0,
      protein: 0,
    },
    defaultItem: {
      name: '',
      category: '',
      fat: 0,
      carbs: 0,
      protein: 0,
    },
  }),
  firebase: {
    minumans : minumanRef
  },
  computed: {
    formTitle(){
      return this.cek === -1 ? 'New Item' : 'Edit Item'
    },
  },
  watch: {
    dialog(val){
      val || this.close()
    },
  },
  methods: {
    close(){
      this.dialog = false
    },
    clear(){
      this.editedItem={}
      this.editedItem.name=''
      this.editedItem.category=''
      this.editedItem.fat=0
      this.editedItem.carbs=0
      this.editedItem.protein=0
      this.cek=-1
    },
    save(){
      if(this.cek>-1)
      {
        minumanRef.child(this.editedIndex).set({name:this.editedItem.name,category:this.editedItem.category,fat:this.editedItem.fat,carbs:this.editedItem.carbs,protein:this.editedItem.protein})
        this.clear()
        }else{
          minumanRef.push({name:this.editedItem.name,category:this.editedItem.category,fat:this.editedItem.fat,carbs:this.editedItem.carbs,protein:this.editedItem.protein}) 
          this.clear()
          }
          
          this.close()
    },
    edit(item){
      this.editedIndex = item['.key']
      this.cek = 0
      this.editedItem = Object.assign({}, item)
      this.dialog = true
    },
    deleteItem(item){
      confirm("Are you sure you want to delete this item?") && minumanRef.child((item['.key'])).remove()
    }
  },
}
</script>